 1	import type { FC } from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	
 4	import { Alert, Text, TextContent, TextVariants } from '@patternfly/react-core';
 5	
 6	const InventoryNotReachable: FC = () => {
 7	  const { t } = useTranslation();
 8	  return (
 9	    <Alert title={t('Inventory')} variant="warning">
10	      <TextContent>
11	        <Text component={TextVariants.p}>
12	          {t(
13	            'Inventory server is not reachable. To troubleshoot, check the Forklift controller pod logs.',
14	          )}
15	        </Text>
16	      </TextContent>
17	    </Alert>
18	  );
19	};
20	
21	export default InventoryNotReachable;

